const KEY = 'iuca_movie_orders';
const USERS_KEY = 'iuca_users';
const SESSION_KEY = 'iuca_current_user';

// --- ФУНКЦИИ ДЛЯ ЗАКАЗОВ (CRUD) ---

export const getOrders = () => {
  const orders = localStorage.getItem(KEY);
  return orders ? JSON.parse(orders) : [];
};

export const getOrderById = (id) => {
  const orders = getOrders();
  return orders.find(order => order.id === id);
};

export const createOrder = (order) => {
  const orders = getOrders();
  const newOrder = { ...order, id: Date.now().toString() };
  orders.push(newOrder);
  localStorage.setItem(KEY, JSON.stringify(orders));
};

export const updateOrder = (id, updatedData) => {
  const orders = getOrders();
  const newOrders = orders.map(order => 
    order.id === id ? { ...order, ...updatedData } : order
  );
  localStorage.setItem(KEY, JSON.stringify(newOrders));
};

export const deleteOrder = (id) => {
  const orders = getOrders();
  const newOrders = orders.filter(order => order.id !== id);
  localStorage.setItem(KEY, JSON.stringify(newOrders));
};

// --- ФУНКЦИИ ДЛЯ ПОЛЬЗОВАТЕЛЕЙ (AUTH) ---

export const registerUser = (userData) => {
  const usersStr = localStorage.getItem(USERS_KEY);
  const users = usersStr ? JSON.parse(usersStr) : [];

  // Проверка: есть ли уже такой логин
  const found = users.find(u => u.username === userData.username);
  if (found) {
    return { success: false, message: 'Пользователь с таким логином уже существует' };
  }

  users.push(userData);
  localStorage.setItem(USERS_KEY, JSON.stringify(users));
  return { success: true };
};

export const loginUser = (username, password) => {
  const usersStr = localStorage.getItem(USERS_KEY);
  const users = usersStr ? JSON.parse(usersStr) : [];

  const user = users.find(u => u.username === username && u.password === password);

  if (user) {
    // Сохраняем текущего пользователя в сессию
    localStorage.setItem(SESSION_KEY, JSON.stringify(user));
    return { success: true };
  } else {
    return { success: false, message: 'Неверный логин или пароль' };
  }
};

export const logoutUser = () => {
  localStorage.removeItem(SESSION_KEY);
};

export const getCurrentUser = () => {
  const userStr = localStorage.getItem(SESSION_KEY);
  return userStr ? JSON.parse(userStr) : null;
};
